package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
	"sync"
	"time"

	"github.com/aymanbagabas/go-pty"
	"github.com/hinshun/vt10x"
)

func main() {
	p, err := pty.New()
	if err != nil {
		fmt.Println("pty.New failed:", err)
		os.Exit(1)
	}
	defer p.Close()

	if err := p.Resize(120, 30); err != nil {
		fmt.Println("resize failed:", err)
	}

	shell := "pwsh"
	args := []string{"-NoLogo", "-NoProfile", "-NoExit", "-Command", "function prompt { 'SPIKE> ' }"}
	if len(os.Args) > 1 {
		shell = os.Args[1]
		args = os.Args[2:]
	}

	if _, err := exec.LookPath(shell); err != nil {
		fmt.Println("shell not found:", shell)
		os.Exit(1)
	}

	cmd := p.Command(shell, args...)
	if err := cmd.Start(); err != nil {
		fmt.Println("start failed:", err)
		os.Exit(1)
	}

	term := vt10x.New(vt10x.WithSize(120, 30))
	var mu sync.Mutex
	var raw strings.Builder

	go func() {
		buf := make([]byte, 4096)
		for {
			n, err := p.Read(buf)
			if n > 0 {
				mu.Lock()
				raw.Write(buf[:n])
				_, _ = term.Write(buf[:n])
				mu.Unlock()
			}
			if err != nil {
				return
			}
		}
	}()

	// wait for prompt
	deadline := time.Now().Add(15 * time.Second)
	for time.Now().Before(deadline) {
		mu.Lock()
		screen := term.String()
		mu.Unlock()
		if strings.Contains(screen, "SPIKE>") {
			fmt.Println("PROMPT DETECTED")
			break
		}
		time.Sleep(100 * time.Millisecond)
	}

	// type a command
	_, _ = p.Write([]byte("echo hello-from-pty\r"))
	deadline = time.Now().Add(10 * time.Second)
	for time.Now().Before(deadline) {
		mu.Lock()
		screen := term.String()
		mu.Unlock()
		if strings.Contains(screen, "hello-from-pty") {
			fmt.Println("ECHO DETECTED")
			break
		}
		time.Sleep(100 * time.Millisecond)
	}

	_, _ = p.Write([]byte("exit\r"))
	done := make(chan error, 1)
	go func() { done <- cmd.Wait() }()
	select {
	case err := <-done:
		fmt.Println("EXITED:", err)
	case <-time.After(10 * time.Second):
		fmt.Println("EXIT TIMEOUT")
		_ = cmd.Process.Kill()
	}

	mu.Lock()
	fmt.Println("--- final screen (last 5 lines) ---")
	lines := strings.Split(strings.TrimRight(term.String(), "\n \t"), "\n")
	start := max(len(lines)-5, 0)
	for _, l := range lines[start:] {
		fmt.Println(strings.TrimRight(l, " "))
	}
	mu.Unlock()
}

