package e2e

import (
	"fmt"
	"regexp"
	"strings"
	"testing"

	"github.com/jandedobbeleer/oh-my-posh/e2e/harness"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// featurePtyCols mirrors the pty width the harness fixes every session to (see
// harness/session.go), used here to assert how close to the right edge the rprompt
// renders.
const featurePtyCols = 120

// TestExitCode boots every shell with the base config, runs its ShellDef.Fail command,
// and asserts the next prompt reports the expected exit code via the "E2E:<code>>"
// template. Shells whose binary is missing or that are unsupported on this platform skip
// cleanly via harness.Start.
func TestExitCode(t *testing.T) {
	for _, sh := range harness.Shells {
		t.Run(sh.Name, func(t *testing.T) {
			require.NotEmpty(t, sh.Fail.Command, "%s: no Fail command configured", sh.Name)

			cfgPath := harness.WriteConfig(t)
			session := harness.Start(t, sh, cfgPath)

			session.WaitForPrompt()
			session.SendLine(sh.Fail.Command)

			expected := fmt.Sprintf("E2E:%d>", sh.Fail.Code)
			session.WaitFor(regexp.MustCompile(regexp.QuoteMeta(expected)))
		})
	}
}

// TestTransient boots every shell with the transient_prompt overlay, types a command, and
// asserts that once the command's output and the following prompt have both landed, the
// screen row that carried the accepted command line was rewritten to start with "TR>" —
// i.e. the primary prompt on that line was replaced by the transient one.
func TestTransient(t *testing.T) {
	const echoedText = "transient-check"

	for _, sh := range harness.Shells {
		t.Run(sh.Name, func(t *testing.T) {
			cfgPath := harness.WriteConfig(t, harness.Transient)
			session := harness.Start(t, sh, cfgPath)

			session.WaitForPrompt()
			session.SendLine("echo " + echoedText)

			// (?s) lets '.' cross line boundaries: this only matches once the echoed
			// output AND a subsequent primary prompt are both on screen, proving the
			// command has fully run and the shell moved on to its next prompt.
			readyRe := regexp.MustCompile(`(?s)` + echoedText + `.*E2E:\d+>`)
			screen := session.WaitFor(readyRe)

			var commandLine string
			for _, line := range session.ScreenLines() {
				if strings.Contains(line, "echo "+echoedText) {
					commandLine = line
					break
				}
			}

			require.NotEmpty(t, commandLine,
				"%s: could not find the accepted command line on screen:\n%s", sh.Name, screen)

			trimmed := strings.TrimLeft(commandLine, " ")
			assert.True(t, strings.HasPrefix(trimmed, "TR>"),
				"%s: command line was not rewritten with the transient prompt: %q", sh.Name, commandLine)
		})
	}
}

// TestRPrompt boots every shell with the rprompt overlay and asserts the fixed "RMARK"
// marker renders on the same screen row as the primary "E2E:0>" prompt, right-aligned
// near the pty's 120th column.
//
// bash only renders a right prompt inside a ble.sh session (gated on the BLE_SESSION_ID
// environment variable, see src/shell/bash.go), which this harness's plain
// `bash --noprofile --rcfile ... -i` session does not provide, so bash is skipped here
// explicitly rather than asserted against.
func TestRPrompt(t *testing.T) {
	for _, sh := range harness.Shells {
		t.Run(sh.Name, func(t *testing.T) {
			if sh.Name == "bash" {
				t.Skip("bash only renders a right prompt inside a ble.sh session; not supported by this harness")
			}

			cfgPath := harness.WriteConfig(t, harness.RPrompt)
			session := harness.Start(t, sh, cfgPath)

			screen := session.WaitForPrompt()

			var promptLine string
			for _, line := range session.ScreenLines() {
				if strings.Contains(line, "E2E:0>") {
					promptLine = line
					break
				}
			}

			require.NotEmpty(t, promptLine,
				"%s: could not find the primary prompt row on screen:\n%s", sh.Name, screen)

			require.Contains(t, promptLine, "RMARK",
				"%s: RMARK not found on the same row as the primary prompt: %q", sh.Name, promptLine)

			trimmed := strings.TrimRight(promptLine, " ")
			assert.True(t, strings.HasSuffix(trimmed, "RMARK"),
				"%s: RMARK is not right-aligned, trimmed row does not end with it: %q", sh.Name, promptLine)

			endCol := strings.LastIndex(promptLine, "RMARK") + len("RMARK")
			assert.InDelta(t, featurePtyCols, endCol, 2,
				"%s: RMARK does not end near column %d (ended at %d): %q", sh.Name, featurePtyCols, endCol, promptLine)
		})
	}
}

